clean_code:
prices = pd.DataFrame({
    'date': ['2020-01-01', '2020-01-02', '2020-01-01', '2020-01-02'],
    'asset': ['AAPL', 'AAPL', 'MSFT', 'MSFT'],
    'price': [100, 101, 200, 201]
})

factors = pd.DataFrame({
    'date': ['2020-01-01', '2020-01-02', '2020-01-01', '2020-01-02'],
    'asset': ['AAPL', 'AAPL', 'MSFT', 'MSFT'],
    'momentum': [0.1, 0.15, 0.2, 0.25]
})

# Merge on BOTH date AND asset
merged = prices.merge(factors, on=['date', 'asset'])
